            if (nums[mid] <= target) {
                best_j = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        int current_len = best_j - i + 1;
        if (current_len > max_len) {
            max_len = current_len;
        }
    }
    return n - max_len;
}
